1	export type Item = { kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone" };
2	
3	export type QuoteStep = { kind: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: QuoteStep[];
8	};
9	
10	export type ScenarioResult = {
11	  results: unknown[];
12	};
13	
14	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const PROCESSING_FEE = 5;
25	
26	function basePremiumFor(item: Item): number {
27	  return BASE_PREMIUM_BY_ITEM[item.kind];
28	}
29	
30	function quoteStep(step: QuoteStep) {
31	  const basePremium = basePremiumFor(step.items[0]);
32	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
33	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
34	  return { kind: "quote" as const, premium };
35	}
36	
37	export function processScenario(scenario: Scenario): ScenarioResult {
38	  const results = scenario.steps.map(quoteStep);
39	  return { results };
40	}
